import{_ as t,o as h,c as i,ai as a,aj as e,ak as g}from"./chunks/framework.CIvSJGYr.js";const u=JSON.parse('{"title":"Giỏ hàng","description":"","frontmatter":{},"headers":[],"relativePath":"cart.md","filePath":"cart.md"}'),c={name:"cart.md"};function o(m,n,r,l,p,s){return h(),i("div",null,[...n[0]||(n[0]=[a('<h1 id="gio-hang" tabindex="-1">Giỏ hàng <a class="header-anchor" href="#gio-hang" aria-label="Permalink to “Giỏ hàng”">​</a></h1><p>Giỏ hàng là nơi bạn có thể xem lại các sản phẩm đã chọn trước khi tiến hành thanh toán.</p><p><img src="'+e+'" alt="gio-hang.png"></p><p>(Lưu ý: Hình ảnh chỉ có tính chất minh họa, giá bán, số lượng, việc sẵn hàng/hết hàng có thể thay đổi theo thời gian)</p><p>Có 5 cách để điều chỉnh số lượng sản phẩm trong giỏ hàng:</p><ul><li>Bấm chọn mua nhiều lần.</li><li>Bấm nút <code>+</code> hoặc <code>-</code> để tăng giảm số lượng tại trang chi tiết sản phẩm.</li><li>Đặt con trỏ chuột vào ô số lượng, dùng Phím mũi tên lên, Phím mũi tên xuống trên bàn phím máy tính để tăng giảm số lượng.</li><li>Chỉnh sửa trực tiếp số lượng sản phẩm trong giỏ hàng.</li><li>Nhập số lượng sản phẩm mong muốn vào ô số lượng.</li></ul><p>Để bỏ một sản phẩm trong giỏ hàng, bấm <code>x</code> .</p><p>Để xóa toàn bộ giỏ hàng, bấm <code>Xóa tất cả</code>.</p><p>Các sản phẩm <code>Hàng xá</code> dùng cho khách hàng mua nông sản như một nguyên liệu sản xuất, hoặc đóng gói OEM, vui lòng liên hệ trước khi mua.</p><h2 id="san-pham-het-hang" tabindex="-1">Sản phẩm hết hàng <a class="header-anchor" href="#san-pham-het-hang" aria-label="Permalink to “Sản phẩm hết hàng”">​</a></h2><p>Giao diện Sản phẩm hết hàng, nút &quot;Thêm vào giỏ&quot; sẽ trở thành &quot;Hết hàng&quot; và có màu đỏ.</p><p><img src="'+g+'" alt="het-hang.png"></p><p>(Lưu ý: Hình ảnh có tính chất minh họa, giá bán, số lượng, khả năng sẵn hàng/hết hàng biến động theo thời gian)</p><h2 id="meo-dung-phim-tat" tabindex="-1">Mẹo dùng phím tắt <a class="header-anchor" href="#meo-dung-phim-tat" aria-label="Permalink to “Mẹo dùng phím tắt”">​</a></h2><ul><li>Từ ô số lượng, bấm phím Tab để chuyển sang Nút bấm &quot;Thêm vào giỏ&quot;, bấm phím Enter để thêm hàng vào giỏ.</li><li>Tại trang chủ, có thể dùng phím tab để chuyển sang sản phẩm kế tiếp liền bên phải hoặc bên dưới. Bấm phím Enter để đi vào xem chi tiết sản phẩm.</li><li>Hầu hết các chức năng trên website đều hỗ trợ phím tắt: Các phím tab, phím Enter. Chúng tôi đã thiết kế thứ tự tab cẩn thận, trong kỹ thuật gọi là tab-index (<a href="https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Global_attributes/tabindex" target="_blank" rel="noreferrer">https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Global_attributes/tabindex</a>). Các form nhập dữ liệu (ví dụ form đặt hàng) có hỗ trợ phím tab.</li></ul><p>Nội dung được cập nhật lúc 14:56 Thứ Bảy, 21 tháng 3, 2026.</p>',16)])])}const b=t(c,[["render",o]]);export{u as __pageData,b as default};
